function normWord(w) {
  return w.toLowerCase().trim();
}

function normExample(e) {
  return e.toLowerCase().trim().replace(/\s+/g, " ");
}

const G1_WORDS = new Set(GRADE1_CARDS.map((c) => normWord(c.word)));
const G1_EXAMPLES = new Set(GRADE1_CARDS.map((c) => normExample(c.example)));

function validateGrade2Cards(cards) {
  const seenWords = new Set();
  const seenExamples = new Set();
  const errors = [];

  for (let i = 0; i < cards.length; i++) {
    const c = cards[i];
    const w = normWord(c.word);
    const ex = normExample(c.example);

    if (seenWords.has(w)) errors.push(`duplicate word in grade 2: "${c.word}"`);
    if (seenExamples.has(ex)) errors.push(`duplicate example in grade 2: "${c.example}"`);
    if (G1_WORDS.has(w)) errors.push(`word overlaps grade 1: "${c.word}"`);
    if (G1_EXAMPLES.has(ex)) errors.push(`example overlaps grade 1: "${c.example}"`);

    seenWords.add(w);
    seenExamples.add(ex);
  }

  if (errors.length) {
    throw new Error(`grade2-cards validation failed:\n${errors.join("\n")}`);
  }
}

/** One card per English word (first occurrence wins). */
export const GRADE2_CARDS = (() => {
  const seen = new Set();
  const out = [];
  for (const card of GRADE2_CARDS_RAW) {
    const key = normWord(card.word);
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(card);
  }
  if (out.length !== GRADE2_CARDS_RAW.length) {
    const dupCount = GRADE2_CARDS_RAW.length - out.length;
    console.warn(`grade2-cards: dropped ${dupCount} duplicate word(s).`);
  }
  validateGrade2Cards(out);
  return out;
})();

export function batchWords(batchNum) {
  const start = (batchNum - 1) * 10;
  return GRADE2_CARDS.slice(start, start + 10).map((c) => c.word);
}
